local mainMod = "SUPER"

local terminal = "ghostty"

hl.monitor({
  output = "",
  mode = "preferred",
  position = "auto",
  scale = 1,
})

hl.bind(mainMod .. " + " .. "Return", hl.dsp.exec_cmd(terminal))

hl.bind(mainMod .. " + " .. "Q", hl.dsp.window.close())

hl.bind(mainMod .. " + " .. "SHIFT" .. " + " .. "E", hl.dsp.exit())

-- --- Input ---

hl.config({
  input = {
    kb_layout = "us",
    follow_mouse = 1,
    touchpad = {
      natural_scroll = true,
      tap_to_click = true,
      disable_while_typing = true,
    },
  },
})

-- --- Layout & borders ---

hl.config({
  general = {
    gaps_in = 5,
    gaps_out = 12,
    border_size = 2,
    layout = "dwindle",
    col = {
      active_border = { colors = { "rgba(cba6f7ee)", "rgba(89b4faee)" }, angle = 45 },
      inactive_border = "rgba(585b70aa)",
    },
  },
})

-- --- decoration ---

hl.config({
  decoration = {
    rounding = 10,
    blur = {
      enabled = true,
      size = 3,
      passes = 1,
    },
  },
})

-- --- Window binds ---

hl.bind(mainMod .. " + " .. " SHIFT" .. " + " .. "V", hl.dsp.window.float())

hl.bind(mainMod .. " + " .. "F", hl.dsp.window.fullscreen())

