-- --- menu ---

local menu = "rofi -show drun"

hl.bind(mainMod .. " + " .. "D", hl.dsp.exec_cmd(menu))

-- --- Autostart ---

-- exec-once = swaybg -m fill -i ~/Pictures.wallpaper.png

-- Autostart
hl.on("hyprland.start", function()
  hl.exec_cmd("swaybg -c 1e1e2e")
  hl.exec_cmd("waybar")
  hl.exec_cmd("mako")
end)

-- start/stop hooks
hl.on("hyprland.start", function()
  hl.exec_cmd("/usr/libexec/hyprpolkitagent")
  hl.exec_cmd("wl-paste --type text --watch cliphist store")
  hl.exec_cmd("wl-paste --type image --watch cliphist store")
  hl.exec_cmd("hypridle")
end)

-- session start/stop (init-system specific; resolved by  yadm per machine)
local session = dofile(os.getenv("HOME") .. "/.config/hypr/session.lua")
session(hl)

-- Special window rules
hl.window_rule({
  match = { class = "hyprpolkitagent" },
  float = true,
  center = true,
})

-- Cursors
